/**
 * Retry utility for fetch requests with exponential backoff
 * Handles transient network errors like ERR_CONNECTION_RESET
 */

interface RetryOptions {
  maxRetries?: number
  initialDelay?: number
  maxDelay?: number
  timeout?: number
  retryableStatuses?: number[]
  retryableErrors?: string[]
}

const DEFAULT_OPTIONS: Required<RetryOptions> = {
  maxRetries: 3,
  initialDelay: 1000, // 1 second
  maxDelay: 10000, // 10 seconds
  timeout: 30000, // 30 seconds
  retryableStatuses: [408, 429, 500, 502, 503, 504],
  retryableErrors: [
    'ERR_CONNECTION_RESET',
    'ERR_CONNECTION_REFUSED',
    'ERR_CONNECTION_CLOSED',
    'ERR_NETWORK_CHANGED',
    'ERR_INTERNET_DISCONNECTED',
    'Failed to fetch',
    'NetworkError',
    'Network request failed',
  ],
}

/**
 * Check if an error is retryable
 */
function isRetryableError(error: any, status?: number, retryableStatuses: number[], retryableErrors: string[]): boolean {
  // Check HTTP status codes
  if (status && retryableStatuses.includes(status)) {
    return true
  }

  // Check error messages
  const errorMessage = error?.message || error?.toString() || ''
  const errorName = error?.name || ''
  
  const allErrorStrings = [errorMessage, errorName].join(' ').toLowerCase()
  
  return retryableErrors.some(retryableError => 
    allErrorStrings.includes(retryableError.toLowerCase())
  )
}

/**
 * Create a timeout promise
 */
function createTimeoutPromise(timeout: number): Promise<never> {
  return new Promise((_, reject) => {
    setTimeout(() => {
      reject(new Error(`Request timeout after ${timeout}ms`))
    }, timeout)
  })
}

/**
 * Sleep for a given number of milliseconds
 */
function sleep(ms: number): Promise<void> {
  return new Promise(resolve => setTimeout(resolve, ms))
}

/**
 * Calculate exponential backoff delay with jitter
 */
function calculateDelay(attempt: number, initialDelay: number, maxDelay: number): number {
  const exponentialDelay = initialDelay * Math.pow(2, attempt)
  const jitter = Math.random() * 0.3 * exponentialDelay // Add up to 30% jitter
  return Math.min(exponentialDelay + jitter, maxDelay)
}

/**
 * Fetch with retry logic and timeout
 */
export async function fetchWithRetry(
  url: string,
  options: RequestInit = {},
  retryOptions: RetryOptions = {}
): Promise<Response> {
  const opts = { ...DEFAULT_OPTIONS, ...retryOptions }
  const { maxRetries, initialDelay, maxDelay, timeout, retryableStatuses, retryableErrors } = opts

  let lastError: any
  let lastResponse: Response | undefined

  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    try {
      // Create abort controller for timeout
      const controller = new AbortController()
      const timeoutId = setTimeout(() => controller.abort(), timeout)

      // Merge abort signal with existing signal
      const signal = options.signal
        ? (() => {
            const combinedController = new AbortController()
            const existingSignal = options.signal!
            existingSignal.addEventListener('abort', () => combinedController.abort())
            controller.signal.addEventListener('abort', () => combinedController.abort())
            return combinedController.signal
          })()
        : controller.signal

      try {
        const response = await Promise.race([
          fetch(url, {
            ...options,
            signal,
            // Add keep-alive header to maintain connections
            headers: {
              ...options.headers,
              'Connection': 'keep-alive',
            },
          }),
          createTimeoutPromise(timeout),
        ])

        clearTimeout(timeoutId)

        // Check if response is retryable
        if (!response.ok && isRetryableError(null, response.status, retryableStatuses, retryableErrors)) {
          lastResponse = response
          
          if (attempt < maxRetries) {
            const delay = calculateDelay(attempt, initialDelay, maxDelay)
            console.warn(`[fetchWithRetry] Request failed with status ${response.status}, retrying in ${delay}ms (attempt ${attempt + 1}/${maxRetries})`, {
              url,
              status: response.status,
              attempt: attempt + 1,
              maxRetries,
            })
            await sleep(delay)
            continue
          }
        }

        // Success or non-retryable error
        return response
      } catch (fetchError: any) {
        clearTimeout(timeoutId)
        
        // Check if error is retryable
        if (isRetryableError(fetchError, undefined, retryableStatuses, retryableErrors)) {
          lastError = fetchError
          
          if (attempt < maxRetries) {
            const delay = calculateDelay(attempt, initialDelay, maxDelay)
            console.warn(`[fetchWithRetry] Network error, retrying in ${delay}ms (attempt ${attempt + 1}/${maxRetries}):`, {
              url,
              error: fetchError?.message || fetchError,
              attempt: attempt + 1,
              maxRetries,
            })
            await sleep(delay)
            continue
          }
        }

        // Non-retryable error or max retries reached
        throw fetchError
      }
    } catch (error: any) {
      lastError = error
      
      // If it's the last attempt, throw the error
      if (attempt === maxRetries) {
        console.error(`[fetchWithRetry] Max retries (${maxRetries}) reached, giving up:`, {
          url,
          error: error?.message || error,
        })
        throw error
      }
    }
  }

  // This should never be reached, but TypeScript needs it
  if (lastResponse) {
    return lastResponse
  }
  throw lastError || new Error('Unknown error in fetchWithRetry')
}
