import React, { useEffect, useState, useCallback } from 'react'
import { fetchWithRetry } from './fetch-retry'

export interface AniAdsProps {
  creator_wallet: string
  app_name: string
  user_wallet_address: string
  api_url?: string // Optional API URL, defaults to production
  onAdClick?: (adId: string, destinationUrl: string) => void // Optional click handler
}

interface Ad {
  id: string
  title: string
  destination_url: string
  image_square: string
  image_portrait: string
  image_landscape: string
  status: 'active' | 'paused' | 'deleting'
  remaining_budget: number
}

export const AniAds: React.FC<AniAdsProps> = ({
  creator_wallet,
  app_name,
  user_wallet_address,
  api_url = 'https://ani-ads.pages.dev/', // Default API URL
  onAdClick,
}) => {
  // Normalize API URL - ensure it doesn't have trailing slash for proper path joining
  const normalizedApiUrl = api_url.replace(/\/+$/, '')
  
  const [ad, setAd] = useState<Ad | null>(null)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)

  // Get image URL - always use image_square (400x100 banner format, 4:1)
  const getImageUrl = (ad: Ad): string | null => {
    return ad.image_square || null
  }

  // Track ad click - fire and forget, don't block navigation
  const trackClick = useCallback(async () => {
    console.log('[AniAds SDK] Click detected', {
      hasAd: !!ad,
      hasWalletAddress: !!user_wallet_address,
      destinationUrl: ad?.destination_url,
      adId: ad?.id
    })

    if (!ad || !user_wallet_address) {
      console.warn('[AniAds SDK] Click tracking skipped - missing ad or wallet address')
      return
    }

    try {
      console.log('[AniAds SDK] Sending click tracking request', {
        ad_id: ad.id,
        creator_wallet: creator_wallet.toLowerCase(),
        app_name,
        user_wallet_address: user_wallet_address.toLowerCase(),
        api_url: `${normalizedApiUrl}/api/ads/click`
      })

      // Track click on backend (fire and forget - don't wait for response)
      // Use retry logic for better reliability
      fetchWithRetry(`${normalizedApiUrl}/api/ads/click`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          ad_id: ad.id,
          creator_wallet: creator_wallet.toLowerCase(),
          app_name,
          user_wallet_address: user_wallet_address.toLowerCase(),
        }),
      }, {
        maxRetries: 2, // Fewer retries for click tracking (not critical)
        timeout: 10000, // 10 second timeout for click tracking
      })
        .then((response) => {
          console.log('[AniAds SDK] Click tracking response', {
            status: response.status,
            ok: response.ok
          })
          if (response.ok && onAdClick) {
            console.log('[AniAds SDK] Calling onAdClick callback')
            onAdClick(ad.id, ad.destination_url)
          }
        })
        .catch((err) => {
          console.error('[AniAds SDK] Error tracking click:', err)
        })
    } catch (err) {
      console.error('[AniAds SDK] Error in trackClick:', err)
    }
  }, [ad, creator_wallet, app_name, user_wallet_address, normalizedApiUrl, onAdClick])

  // Get image - always use banner format (400x100, 4:1)
  const getBestImage = (ad: Ad): string | null => {
    return getImageUrl(ad)
  }

  // Track impression when ad is displayed
  const trackImpression = useCallback(async (adId: string) => {
    if (!adId || !creator_wallet || !app_name || !user_wallet_address) return

    try {
      await fetchWithRetry(`${normalizedApiUrl}/api/ads/impression`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          ad_id: adId,
          creator_wallet: creator_wallet.toLowerCase(),
          app_name,
          user_wallet_address: user_wallet_address.toLowerCase(),
        }),
      }, {
        maxRetries: 2, // Fewer retries for impression tracking (not critical)
        timeout: 10000, // 10 second timeout for impression tracking
      })
      // Don't show errors to user - impression tracking is not critical
    } catch (err) {
      console.error('Error tracking impression:', err)
      // Silently fail - impression tracking should not break the ad display
    }
  }, [creator_wallet, app_name, user_wallet_address, normalizedApiUrl])

  // Fetch ad only once when component mounts or when creator_wallet/app_name changes
  useEffect(() => {
    let cancelled = false
    
    const loadAd = async () => {
      if (!creator_wallet || !app_name) {
        setLoading(false)
        return
      }

      // Check if user_wallet_address is provided (required)
      if (!user_wallet_address) {
        console.warn('[AniAds SDK] No user_wallet_address provided - ads will not be shown')
        setLoading(false)
        setAd(null)
        setError('user_wallet_address is required')
        return
      }

      // Note: Verification check is now optional - unverified users can also see ads
      // Verification status will be checked server-side and affects earnings (5% vs 2%)
      // We still log verification status for debugging
      try {
        // Dynamically import @worldcoin/minikit-js to avoid bundling issues
        const { getIsUserVerified } = await import('@worldcoin/minikit-js')
        
        console.log('[AniAds SDK] Checking Address Book verification for user:', user_wallet_address.toLowerCase())
        const isUserVerified = await getIsUserVerified(user_wallet_address)
        console.log('[AniAds SDK] Address Book verification result:', {
          user_wallet_address: user_wallet_address.toLowerCase(),
          isVerified: isUserVerified,
          timestamp: new Date().toISOString()
        })
        
        if (!isUserVerified) {
          console.log('[AniAds SDK] User is NOT verified in Address Book - ads will still be shown but with lower earnings (2% instead of 5%)')
        } else {
          console.log('[AniAds SDK] User is verified in Address Book - proceeding to load ads with full earnings (5%)')
        }
      } catch (verificationError: any) {
        // If verification check fails, continue anyway - unverified users can still see ads
        console.warn('[AniAds SDK] Error checking Address Book verification - continuing anyway:', {
          user_wallet_address: user_wallet_address.toLowerCase(),
          error: verificationError?.message || verificationError,
          timestamp: new Date().toISOString()
        })
        // Don't block - continue to load ads
      }

      try {
        setLoading(true)
        setError(null)

        // Use retry logic for better reliability with network errors
        const response = await fetchWithRetry(`${normalizedApiUrl}/api/ads/sdk`, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify({
            creator_wallet: creator_wallet.toLowerCase(),
            app_name,
            user_wallet_address: user_wallet_address.toLowerCase(),
          }),
        }, {
          maxRetries: 3, // Retry up to 3 times for ad loading (critical)
          timeout: 20000, // 20 second timeout for ad loading
        })

        if (cancelled) return

        if (!response.ok) {
          const errorData = await response.json().catch(() => ({}))
          throw new Error(errorData.error || `HTTP ${response.status}: Failed to fetch ads`)
        }

        const data = await response.json()
        
        if (cancelled) return
        
        if (data.ad) {
          setAd(data.ad)
          setError(null) // Clear any previous errors
          
          // Track impression when ad is loaded and displayed
          trackImpression(data.ad.id)
        } else {
          // No ad available, but not an error - just don't show anything
          setAd(null)
          setError(null)
        }
      } catch (err) {
        if (cancelled) return
        console.error('Error fetching ad:', err)
        const errorMessage = err instanceof Error ? err.message : 'Failed to load ad'
        
        // Provide more helpful error messages for network errors
        if (errorMessage.includes('timeout') || errorMessage.includes('ERR_CONNECTION')) {
          setError('Network connection issue. Please check your internet connection and try again.')
        } else {
          setError(errorMessage)
        }
        setAd(null)
      } finally {
        if (!cancelled) {
          setLoading(false)
        }
      }
    }

    loadAd()

    return () => {
      cancelled = true
    }
  }, [creator_wallet, app_name, user_wallet_address, normalizedApiUrl]) // Only depend on props, not derived values

  // Don't show anything while loading, on error, or when no ad - only render when ad is ready
  if (loading || error || !ad) {
    return null
  }

  const imageUrl = getBestImage(ad)

  if (!imageUrl) {
    return null
  }

  // Use an anchor tag for webview compatibility
  // Let the link navigate normally, track click in parallel
  return (
    <a
      href={ad.destination_url}
      target="_blank"
      rel="noopener noreferrer"
      onClick={(e) => {
        console.log('[AniAds SDK] Anchor tag onClick fired', {
          destinationUrl: ad.destination_url,
          href: e.currentTarget.href
        })
        trackClick()
        // Don't prevent default - let the link navigate normally
      }}
      style={{
        display: 'inline-block',
        width: '100%',
        cursor: 'pointer',
        borderRadius: '8px',
        overflow: 'hidden',
        transition: 'transform 0.2s, box-shadow 0.2s',
        textDecoration: 'none',
      }}
      onMouseEnter={(e) => {
        e.currentTarget.style.transform = 'scale(1.02)'
        e.currentTarget.style.boxShadow = '0 4px 12px rgba(0,0,0,0.15)'
      }}
      onMouseLeave={(e) => {
        e.currentTarget.style.transform = 'scale(1)'
        e.currentTarget.style.boxShadow = 'none'
      }}
    >
      <img
        src={imageUrl}
        alt={ad.title}
        style={{
          width: '100%',
          height: 'auto',
          display: 'block',
        }}
        loading="lazy"
      />
    </a>
  )
}

export default AniAds
